"""
TDD Stage: full_standardize
Add compute Phases 4-8: square centered (c_3->c_24, WaitUpfrontNoPop), reduce_row variance (c_24->c_4), add_scalar epsilon (c_4+c_7->c_25), rsqrt (c_25->c_5), mul_col (c_3*c_5->c_6). Complete row-wise standardization.
"""

import pytest
import ttnn


from .row_centralize import row_centralize


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 64), id="1x1x32x64"),
        pytest.param((1, 1, 64, 128), id="1x1x64x128"),
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
    ],
)
def test_full_standardize(device, shape):
    """Verify full row-wise standardization (all 9 compute phases)."""
    import torch

    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)

    mean = torch_input.mean(dim=-1, keepdim=True)
    centered = torch_input - mean
    var = (centered**2).mean(dim=-1, keepdim=True)
    expected = centered * (var + 1e-5).rsqrt()

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )

    ttnn_output = row_centralize(ttnn_input)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
